import{c as a,O as n,i,m as s}from"./chunks/framework.BWIk71Uc.js";const h=JSON.parse('{"title":"Linux","description":"Linux usage notes covering common commands, file permissions, process management, and network commands.","frontmatter":{"title":"Linux","description":"Linux usage notes covering common commands, file permissions, process management, and network commands.","date":"2026-05-29T00:00:00.000Z","tags":["Linux"],"category":"knowledge","status":"draft","outline":"deep","lastUpdated":true},"headers":[],"relativePath":"en/notes/tools/linux.md","filePath":"en/notes/tools/linux.md","lastUpdated":1780128182000}'),o={name:"en/notes/tools/linux.md"};function r(t,e,l,m,c,d){return n(),i("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1780012800000"},[...e[0]||(e[0]=[s('<h1 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to “Linux”">​</a></h1><p>This document records notes on Linux usage.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to “Learning Objectives”">​</a></h2><ul><li>Master commonly used commands</li><li>Understand file permissions and user management</li><li>Familiarize with process management and network commands</li><li>Be able to write simple Shell scripts</li></ul><h2 id="core-content" tabindex="-1">Core Content <a class="header-anchor" href="#core-content" aria-label="Permalink to “Core Content”">​</a></h2><h3 id="common-commands" tabindex="-1">Common Commands <a class="header-anchor" href="#common-commands" aria-label="Permalink to “Common Commands”">​</a></h3><ul><li>File operations: ls, cd, cp, mv, rm, mkdir</li><li>Text processing: cat, grep, awk, sed</li><li>Compression and decompression: tar, gzip, zip</li><li>System information: uname, top, df, free</li></ul><h3 id="file-permissions" tabindex="-1">File Permissions <a class="header-anchor" href="#file-permissions" aria-label="Permalink to “File Permissions”">​</a></h3><ul><li>Permission representation: rwx</li><li>chmod: modify permissions</li><li>chown: change owner</li><li>User and user group management</li></ul><h3 id="process-management" tabindex="-1">Process Management <a class="header-anchor" href="#process-management" aria-label="Permalink to “Process Management”">​</a></h3><ul><li>ps: view processes</li><li>kill: terminate processes</li><li>systemctl: service management</li><li>nohup: run in background</li></ul><h3 id="network-commands" tabindex="-1">Network Commands <a class="header-anchor" href="#network-commands" aria-label="Permalink to “Network Commands”">​</a></h3><ul><li>ping: network connectivity</li><li>curl: HTTP requests</li><li>netstat: network status</li><li>ssh: remote connection</li></ul><h2 id="work-in-progress" tabindex="-1">Work in Progress <a class="header-anchor" href="#work-in-progress" aria-label="Permalink to “Work in Progress”">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Work in Progress</p><p>This page is still being improved. More project-based examples and troubleshooting notes will be added later.</p></div>',15)])])}const u=a(o,[["render",r]]);export{h as __pageData,u as default};
